import React, { useState } from "react";
import Marquee from "react-fast-marquee";
import "./App.css";

function importAll(r) {
  return r.keys().map((fileName) => ({
    src: r(fileName).default,
    text: `Text for ${fileName.slice(2, -4)}`,
  }));
}

const images = importAll(require.context("./images", false, /\.(png|jpe?g|svg)$/));

function MarqueeExample() {
  const [isHovered, setIsHovered] = useState(false);

  function handleClick(imageIndex) {
    window.location.href = `page${imageIndex + 1}.html`;
  }

  return (
    <div className="marquee-container">
      <Marquee
        gradient={false}
        speed={40}
        direction="left"
        pauseOnHover={true}
        // clickOnHover={true}
        pauseOnClick={true}
      >
        {images.map((image, index) => (
          <div
            key={index}
            className="marquee-item"
            // onClick={() => handleClick(index)}
          >
            <div className="marquee-item-box">
              <img src={image.src} alt="example" />
              <span>
                <p>{image.text}</p>
              </span>
            </div>
          </div>
        ))}
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
